import PackageDescription

let package = Package(
    name: "AudioCaptureKit",
    platforms: [
        .macOS(.v14)
    ],
    products: [
        .library(
            name: "AudioCaptureKit",
            targets: ["AudioCaptureKit"]
        )
    ],
    dependencies: [
        .package(url: "https://github.com/apple/swift-crypto.git", from: "4.0.0"),
        .package(url: "https://github.com/apple/swift-testing.git", from: "6.0.0")
    ],
    targets: [
        .target(
            name: "AudioCaptureKit",
            dependencies: [
                .product(name: "Crypto", package: "swift-crypto")
            ],
            path: "macOS/Sources/AudioCaptureKit"
        ),
        .testTarget(
            name: "AudioCaptureKitTests",
            dependencies: [
                "AudioCaptureKit",
                .product(name: "Testing", package: "swift-testing")
            ],
            path: "macOS/Tests/AudioCaptureKitTests"
        )
    ]
)

